    Process and evaluate a user-provided arithmetic expression securely.

    - Validates the expression with parse_expression.
    - Evaluates it with evaluate_safe_expression.
    - Returns the numeric result on success, otherwise 'Processing Failed!'.
    """
    if not isinstance(expr, str):
        return "Processing Failed!"
    if not parse_expression(expr):
        return "Processing Failed!"
    result = evaluate_safe_expression(expr)
    if isinstance(result, str):
        return "Processing Failed!"
    return result

