    if not isinstance(expr, str):
        return "Processing Failed!"
    text = expr.strip()
    if not text:
        return "Processing Failed!"
    if len(text) > 10000:
        return "Processing Failed!"
    try:
        tree = ast.parse(text, mode="eval")
    except SyntaxError:
        return "Processing Failed!"

    ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
    }
    uops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def eval_node(node, depth=0):
        if depth > 1000:
            raise ValueError("expression too deep")
        if isinstance(node, ast.Expression):
            return eval_node(node.body, depth + 1)
        if isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in ops:
                raise ValueError("unsupported operator")
            left = eval_node(node.left, depth + 1)
            right = eval_node(node.right, depth + 1)
            return ops[op_type](left, right)
        if isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in uops:
                raise ValueError("unsupported unary operator")
            operand = eval_node(node.operand, depth + 1)
            return uops[op_type](operand)
        if isinstance(node, ast.Constant):
            val = node.value
            if isinstance(val, bool):
                raise ValueError("booleans not allowed")
            if isinstance(val, (int, float)):
                return val
            raise ValueError("unsupported constant")
        if hasattr(ast, "Num") and isinstance(node, ast.Num):  # pragma: no cover
            return node.n
        # Disallow everything else (Names, Calls, Attributes, Subscripts, etc.)
        raise ValueError("unsupported expression")

    try:
        result = eval_node(tree)
        if isinstance(result, float) and not math.isfinite(result):
            return "Processing Failed!"
        return result
    except Exception:
        return "Processing Failed!"

